import matplotlib.pyplot as plt

def visualize_coco_skeleton(keypoints_1d, save_path=None):
    """
    keypoints_1d: list of length 34
                  format [x1, y1, x2, y2, ..., x17, y17]
    save_path:    str or None, e.g. "skeleton.png" / "skeleton.pdf"
                  if None, only visualize; otherwise save image
    """
    assert len(keypoints_1d) == 34, "Input must be a 34-length list"

    # reshape to (17, 2)
    keypoints = [(keypoints_1d[i], keypoints_1d[i + 1])
                 for i in range(0, 34, 2)]

    # COCO 17-keypoint skeleton (0-based index)
    skeleton = [
        (0, 1), (0, 2), (1, 3), (2, 4),      # head
        (5, 6),                              # shoulders
        (5, 7), (7, 9),                      # left arm
        (6, 8), (8, 10),                     # right arm
        (5, 11), (6, 12),                    # torso
        (11, 12),                            # hips
        (11, 13), (13, 15),                  # left leg
        (12, 14), (14, 16)                   # right leg
    ]

    plt.figure()
    xs, ys = zip(*keypoints)
    plt.scatter(xs, ys)

    for i, j in skeleton:
        plt.plot(
            [keypoints[i][0], keypoints[j][0]],
            [keypoints[i][1], keypoints[j][1]]
        )

    plt.gca().invert_yaxis()   # image coordinate system
    plt.axis("equal")
    plt.title("COCO 17-Keypoint Skeleton")

    # ===== 保存图片 =====
    if save_path is not None:
        plt.savefig(
            save_path,
            dpi=300,
            bbox_inches="tight"
        )

    plt.show()
    plt.close()

# ===== 示例 =====
# keypoints_1d = [
#     320, 120, 315, 160, 330, 158, 300, 200, 350, 198,
#     280, 260, 370, 258, 290, 330, 360, 328,
#     305, 360, 335, 360, 300, 430, 340, 430,
#     310, 500, 330, 500, 295, 580, 345, 580
# ]

visualize_coco_skeleton(keypoints_1d, "skeleton.png")
